pub async fn get_one_user(pool: &sqlx::PgPool, id: i32) -> Result<GetOneUserRow, sqlx::Error> {
    sqlx::query_as!(GetOneUserRow, "SELECT id, name FROM users WHERE id = $1", id)
        .fetch_one(pool)
        .await
}

